import{_ as p,c as e,b0 as r,o as t}from"./chunks/framework.DIXa3MoD.js";const d=JSON.parse('{"title":"プライバシーポリシー","description":"","frontmatter":{},"headers":[],"relativePath":"ja/privacy/index.md","filePath":"ja/privacy/index.md","lastUpdated":1769153511000}'),o={name:"ja/privacy/index.md"};function n(i,a,l,s,m,h){return t(),e("div",null,a[0]||(a[0]=[r('<h1 id="プライバシーポリシー" tabindex="-1">プライバシーポリシー <a class="header-anchor" href="#プライバシーポリシー" aria-label="Permalink to &quot;プライバシーポリシー&quot;">​</a></h1><p>（改定日：2022年7月16日、施行日：2022年7月16日）</p><p>Hamはお客様の個人情報の保護を重視しています。サービス提供のために必要な場合に限り、一定の情報をお願いすることがあります。本プライバシーポリシーは、そのような場合のデータ収集および利用について説明します。本ポリシーはHamアプリのすべての関連サービスに適用されます。</p><h3 id="個人情報の収集" tabindex="-1">個人情報の収集 <a class="header-anchor" href="#個人情報の収集" aria-label="Permalink to &quot;個人情報の収集&quot;">​</a></h3><p>お客様を識別できる情報（個人情報）や連絡先情報が必要な場合、事前に同意を取得します。</p><p>Hamはお客様の個人情報を収集しません。ただし、アプリの性能向上や利用状況の統計のために、個人情報が第三者と共有される場合があります。Hamが利用している第三者サービスは以下の通りです。</p><p><strong>AMap（高徳）オープンプラットフォーム位置情報SDK</strong></p><p>第三者名：高徳ソフトウェア有限公司</p><p>利用目的：位置情報を取得して天気を表示</p><p>機能種別：位置情報と天気検索</p><p>関与する個人情報：WLAN状態情報、位置情報</p><p>プライバシーポリシーリンク：<a href="https://lbs.amap.com/pages/privacy/" target="_blank" rel="noreferrer">https://lbs.amap.com/pages/privacy/</a></p><br><p><strong>友盟（UMeng）SDK</strong></p><p>サービス種別：統計分析、アプリ性能分析</p><p>収集する個人情報：デバイス情報</p><p>プライバシーポリシーリンク：<a href="https://www.umeng.com/page/policy" target="_blank" rel="noreferrer">https://www.umeng.com/page/policy</a></p><h3 id="個人情報の管理" tabindex="-1">個人情報の管理 <a class="header-anchor" href="#個人情報の管理" aria-label="Permalink to &quot;個人情報の管理&quot;">​</a></h3><p>Hamは、法律で要求される場合、またはHamの関連サービス規約・ソフトウェアライセンスに合致する場合に限り、お客様の個人情報を開示します。あるいは、以下のために開示が必要だと合理的に判断できる場合に限ります。</p><p>(a) 法律の明文規定や本アプリに適用される法的手続に従うため</p><p>(b) Hamの関連サービス規約またはソフトウェアライセンスに従うため</p><p>(c) Hamの権利または財産を保護するため</p><p>(d) 緊急時にHamスタッフ、Ham製品またはサービスの利用者、あるいは公衆の安全を保護するため</p><p>本ポリシーに記載された場合を除き、Hamは許可なく個人情報を第三者と共有しません。</p><h3 id="個人情報の安全" tabindex="-1">個人情報の安全 <a class="header-anchor" href="#個人情報の安全" aria-label="Permalink to &quot;個人情報の安全&quot;">​</a></h3><p>個人情報の安全保護を徹底しています。各種セキュリティ技術と手続を利用し、未承認のアクセス、使用、漏えいを防止します。</p><h3 id="免責事項" tabindex="-1">免責事項 <a class="header-anchor" href="#免責事項" aria-label="Permalink to &quot;免責事項&quot;">​</a></h3><p>以下の事由について、Hamは法的責任を負いません。</p><p>Hamが法律や政府の要請に従って個人情報を提供する場合</p><p>Ham以外の原因による個人情報の漏えい</p><p>Hamのサービス規約および本ポリシーに記載された状況に基づき第三者が個人情報を利用したことにより生じた紛争</p><p>ハッキング、ウイルス感染、政府による規制により一時的にサービスが停止した場合</p><p>不可抗力による一切の結果</p><p>その他、Hamのサービス規約および本ポリシーに記載された免責事由</p><h3 id="改定" tabindex="-1">改定 <a class="header-anchor" href="#改定" aria-label="Permalink to &quot;改定&quot;">​</a></h3><p>本プライバシーポリシーは必要に応じて改定されます。最新の内容をご確認いただくことを推奨します。将来の改定については個別の通知は行わず、過去に収集したデータの取り扱い方針を遡って変更することはありません。</p>',36)]))}const _=p(o,[["render",n]]);export{d as __pageData,_ as default};
